// ===== UBIKAIS 전체 데이터 크롤링 =====
// 로그인 후 받은 쿠키로 NOTAM + Weather + FPL + AeroData + ATFM 수집
// 주의: n8n 환경변수에 NODE_TLS_REJECT_UNAUTHORIZED=0 설정 필요 (SSL)

const BASE_URL = 'https://ubikais.fois.go.kr:8030';
const helpers = this.helpers;

// 이전 노드에서 쿠키 추출
const loginResponse = $input.first().json;
let cookies = '';
if (loginResponse.headers && loginResponse.headers['set-cookie']) {
  const setCookies = loginResponse.headers['set-cookie'];
  cookies = (Array.isArray(setCookies) ? setCookies : [setCookies])
    .map(c => c.split(';')[0])
    .join('; ');
}

// 날짜 헬퍼
const now = new Date();
const y = now.getFullYear();
const m = String(now.getMonth() + 1).padStart(2, '0');
const d = String(now.getDate()).padStart(2, '0');
const hh = String(now.getHours()).padStart(2, '0');
const mm = String(now.getMinutes()).padStart(2, '0');
const ss = String(now.getSeconds()).padStart(2, '0');
const today = `${y}-${m}-${d}`;
const todayCompact = `${y}${m}${d}`;
const yy = String(y).slice(2);
const todayShort = `${yy}${m}${d}`;
const timestamp = `${y}${m}${d}_${hh}${mm}${ss}`;

// 날짜 범위 (N일 전 ~ 오늘)
function dateRange(daysBack) {
  const from = new Date(now);
  from.setDate(from.getDate() - daysBack);
  const fy = from.getFullYear();
  const fm = String(from.getMonth() + 1).padStart(2, '0');
  const fd = String(from.getDate()).padStart(2, '0');
  return { from: `${fy}-${fm}-${fd}`, to: today };
}

// UBIKAIS API 호출 함수
async function crawl(endpoint, params) {
  const qs = Object.entries(params).map(([k, v]) => encodeURIComponent(k) + "=" + encodeURIComponent(String(v))).join("&");
  const fullUrl = BASE_URL + endpoint + "?" + qs;
  try {
    const response = await helpers.httpRequest({
      url: fullUrl,
      method: 'GET',
      headers: {
        'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36',
        'Accept': 'application/json, text/javascript, */*; q=0.01',
        'X-Requested-With': 'XMLHttpRequest',
        'Referer': BASE_URL + '/sysUbikais/biz/main.ubikais',
        'Cookie': cookies
      },
      skipSslCertificateValidation: true,
      json: true
    });
    return response;
  } catch (e) {
    return { error: e.message };
  }
}

function sleep(ms) {
  return new Promise(r => setTimeout(r, ms));
}

// ===== 크롤링 결과 객체 =====
const allData = {
  crawled_at: now.toISOString(),
  data: {
    main: { departures: {}, arrivals: {}, weather: {} },
    notam: { fir: {}, ad: {}, snow: null, prohibited: null, sequence: {} },
    flight_plans: {},
    weather: { metar: {}, taf: {}, sigmet: null },
    aero_data: { airports: {}, runways: {}, aprons: {}, navaids: null, obstacles: null },
    atfm: {}
  }
};

// 공항 목록
const mainAirports = ['RKSI', 'RKSS', 'RKPK', 'RKPC', 'RKPU'];
const allAirports = [
  'RKSI', 'RKSS', 'RKTU', 'RKNY', 'RKJK', 'RKNW',
  'RKPC', 'RKPK', 'RKTN', 'RKJJ', 'RKJY', 'RKPU',
  'RKTH', 'RKPS', 'RKJB', 'RKTL'
];

// ========== 1. 메인 페이지 데이터 (주요 공항) ==========
for (const apt of mainAirports) {
  allData.data.main.departures[apt] = await crawl('/main/selectIfr.fois', { depArr: 'dep', apIcao: apt });
  allData.data.main.arrivals[apt] = await crawl('/main/selectIfr.fois', { depArr: 'arr', apIcao: apt });
  allData.data.main.weather[apt] = await crawl('/main/selectMetSpec.fois', { apIcao: apt });
  await sleep(500);
}

// ========== 2. NOTAM ==========
// 2a. FIR NOTAM (시리즈: C, A, D)
for (const series of ['C', 'A', 'D']) {
  const result = await crawl('/sysUbikais/biz/nps/selectNotamRecFir.fois', {
    downloadYn: '1', srchFir: 'RKRR', srchAd: 'RKRR', srchSeries: series,
    srchValid: today, srchValidsh: todayShort + '2359',
    srchValidsh2: todayShort + '0000', srchValid2: '1',
    cmd: 'get-records', limit: '1000', offset: '0'
  });
  if (result && result.records) allData.data.notam.fir[series] = result;
  await sleep(300);
}

// 2b. AD NOTAM (주요 공항)
for (const airport of mainAirports) {
  const result = await crawl('/sysUbikais/biz/nps/selectNotamRecAd.fois', {
    downloadYn: '1', srchFir: 'RKRR', srchSeries: 'C', srchAd: airport,
    srchValid: today, srchValidsh: todayShort + '2359',
    srchValidsh2: todayShort + '0000', srchValid2: '1',
    cmd: 'get-records', limit: '1000', offset: '0'
  });
  if (result) allData.data.notam.ad[airport] = result;
  await sleep(300);
}

// 2c. SNOWTAM
allData.data.notam.snow = await crawl('/sysUbikais/biz/nps/selectNotamRecSnow.fois', {
  downloadYn: '1', printYn: '', srchOriginator: '', srchSeq: '',
  srchAd: '', srchValidFrom: String(y),
  cmd: 'get-records', limit: '1000', offset: '0'
});

// 2d. 금지구역 NOTAM
allData.data.notam.prohibited = await crawl('/sysUbikais/biz/nps/selectRecOffZone.fois', {
  downloadYn: '1', srchFir: 'RKRR', srchSeries: 'D', srchQcode: 'QRP',
  srchValid: today, srchValidsh: todayShort + '2359',
  srchValidsh2: todayShort + '0000', srchValid2: '1',
  cmd: 'get-records', limit: '1000', offset: '0'
});

// 2e. Sequence List (시리즈: C, A, D)
for (const series of ['C', 'A', 'D']) {
  const result = await crawl('/sysUbikais/biz/nps/selectNotamRecSeq.fois', {
    downloadYn: '1', printYn: '', srchFir: 'RKRR', srchSeries: series,
    srchSeq: '', srchYear: yy,
    cmd: 'get-records', limit: '1000', offset: '0'
  });
  if (result && result.records) allData.data.notam.sequence[series] = result;
  await sleep(300);
}

// ========== 3. 비행 계획 (i-ARO) ==========
allData.data.flight_plans = {
  ifr_departures: await crawl('/sysUbikais/biz/fpl/selectDep.fois', {
    today: todayCompact, cmd: 'get-records', limit: 1000, offset: 0
  }),
  ifr_arrivals: await crawl('/sysUbikais/biz/fpl/selectArr.fois', {
    today: todayCompact, cmd: 'get-records', limit: 1000, offset: 0
  }),
  vfr: await crawl('/sysUbikais/biz/fpl/selectVfrFpl.fois', {
    today: todayCompact, cmd: 'get-records', limit: 1000, offset: 0
  }),
  ulp_lsa: await crawl('/sysUbikais/biz/fpl/selectUlpFpl.fois', {
    today: todayCompact, cmd: 'get-records', limit: 1000, offset: 0
  })
};
await sleep(500);

// ========== 4. 기상 데이터 (주요 공항) ==========
const wx2 = dateRange(2);
const wx7 = dateRange(7);

for (const apt of mainAirports) {
  allData.data.weather.metar[apt] = await crawl('/sysUbikais/biz/wis/selectMetar.fois', {
    today: todayCompact, srchApIcao: apt,
    srchDateFr: wx2.from, srchDateTo: wx2.to,
    cmd: 'get-records', limit: 500, offset: 0
  });
  allData.data.weather.taf[apt] = await crawl('/sysUbikais/biz/wis/selectTaf.fois', {
    today: todayCompact, srchApIcao: apt,
    srchDateFr: wx2.from, srchDateTo: wx2.to,
    cmd: 'get-records', limit: 500, offset: 0
  });
  await sleep(300);
}

allData.data.weather.sigmet = await crawl('/sysUbikais/biz/wis/selectSigmet.fois', {
  srchDateFr: wx7.from, srchDateTo: wx7.to,
  cmd: 'get-records', limit: 100, offset: 0
});

// ========== 5. AERO-DATA (전체 공항) ==========
for (const apt of allAirports) {
  allData.data.aero_data.airports[apt] = await crawl('/sysUbikais/biz/ais/airport/select.fois', {
    today: todayCompact, srchAd: apt
  });
  allData.data.aero_data.runways[apt] = await crawl('/sysUbikais/biz/ais/runway/select.fois', {
    today: todayCompact, srchAd: apt
  });
  allData.data.aero_data.aprons[apt] = await crawl('/sysUbikais/biz/ais/apron/select.fois', {
    today: todayCompact, srchAd: apt
  });
  await sleep(300);
}

allData.data.aero_data.navaids = await crawl('/sysUbikais/biz/ais/navaid/select.fois', {
  today: todayCompact, cmd: 'get-records', limit: 500, offset: 0
});

allData.data.aero_data.obstacles = await crawl('/sysUbikais/biz/ais/obst/select.fois', {
  today: todayCompact, cmd: 'get-records', limit: 500, offset: 0
});

// ========== 6. ATFM ==========
allData.data.atfm = {
  daily_plan: await crawl('/sysUbikais/biz/atfms/selectAdp.fois', {
    today: todayCompact, cmd: 'get-records', limit: 100, offset: 0
  }),
  messages: await crawl('/sysUbikais/biz/atfms/selectDfl.fois', {
    today: todayCompact, cmd: 'get-records', limit: 100, offset: 0
  })
};

// ========== 결과 반환 ==========
// 통계 계산
const stats = {
  main: mainAirports.length,
  notam_fir: Object.keys(allData.data.notam.fir).length,
  notam_ad: Object.keys(allData.data.notam.ad).length,
  snowtam: allData.data.notam.snow ? 1 : 0,
  prohibited: allData.data.notam.prohibited ? 1 : 0,
  flight_plans: 4,
  weather_metar: Object.keys(allData.data.weather.metar).length,
  weather_taf: Object.keys(allData.data.weather.taf).length,
  sigmet: allData.data.weather.sigmet ? 1 : 0,
  aero_airports: Object.keys(allData.data.aero_data.airports).length,
  aero_navaids: allData.data.aero_data.navaids ? 1 : 0,
  aero_obstacles: allData.data.aero_data.obstacles ? 1 : 0,
  atfm: 2
};

return [{
  json: {
    fullData: allData,
    s3Key: `notam_complete/${timestamp}/ubikais_full_${timestamp}.json`,
    s3KeyLatest: `notam_complete/latest/ubikais_full_latest.json`,
    // 개별 파일 S3 키
    s3Keys: {
      notam: `notam_complete/${timestamp}/notam_${timestamp}.json`,
      notamLatest: `notam_complete/latest/notam_current.json`,
      weather: `notam_complete/${timestamp}/weather_${timestamp}.json`,
      weatherLatest: `notam_complete/latest/weather_current.json`,
      flightPlans: `notam_complete/${timestamp}/flight_plans_${timestamp}.json`,
      flightPlansLatest: `notam_complete/latest/flight_schedule.json`,
      aeroData: `notam_complete/${timestamp}/aero_data_${timestamp}.json`,
      aeroDataLatest: `notam_complete/latest/aero_data_current.json`
    },
    timestamp: timestamp,
    date: today,
    stats: stats
  }
}];

// 전체 데이터를 Supabase 업로드용 바이너리로 변환
// 전체 + 개별 파일 모두 생성
const item = $input.first().json;
const fullData = item.fullData;

// 전체 데이터 JSON
const fullJson = JSON.stringify(fullData, null, 2);
const fullBase64 = Buffer.from(fullJson, 'utf-8').toString('base64');

// 개별 파일: NOTAM
const notamJson = JSON.stringify(fullData.data.notam, null, 2);
const notamBase64 = Buffer.from(notamJson, 'utf-8').toString('base64');

// 개별 파일: Weather
const weatherJson = JSON.stringify(fullData.data.weather, null, 2);
const weatherBase64 = Buffer.from(weatherJson, 'utf-8').toString('base64');

// 개별 파일: Flight Plans
const fplJson = JSON.stringify(fullData.data.flight_plans, null, 2);
const fplBase64 = Buffer.from(fplJson, 'utf-8').toString('base64');

// 개별 파일: Aero Data
const aeroJson = JSON.stringify(fullData.data.aero_data, null, 2);
const aeroBase64 = Buffer.from(aeroJson, 'utf-8').toString('base64');

// 여러 아이템으로 반환 (각각 Supabase 업로드 대상)
return [
  // 1. 전체 데이터 (타임스탬프)
  {
    json: { s3Key: item.s3Key, fileType: 'full_timestamped', stats: item.stats },
    binary: { data: { data: fullBase64, mimeType: 'application/json', fileName: `ubikais_full_${item.timestamp}.json` } }
  },
  // 2. 전체 데이터 (최신)
  {
    json: { s3Key: item.s3KeyLatest, fileType: 'full_latest', stats: item.stats },
    binary: { data: { data: fullBase64, mimeType: 'application/json', fileName: 'ubikais_full_latest.json' } }
  },
  // 3. NOTAM (타임스탬프)
  {
    json: { s3Key: item.s3Keys.notam, fileType: 'notam_timestamped' },
    binary: { data: { data: notamBase64, mimeType: 'application/json', fileName: `notam_${item.timestamp}.json` } }
  },
  // 4. NOTAM (최신)
  {
    json: { s3Key: item.s3Keys.notamLatest, fileType: 'notam_latest' },
    binary: { data: { data: notamBase64, mimeType: 'application/json', fileName: 'notam_current.json' } }
  },
  // 5. Weather (타임스탬프)
  {
    json: { s3Key: item.s3Keys.weather, fileType: 'weather_timestamped' },
    binary: { data: { data: weatherBase64, mimeType: 'application/json', fileName: `weather_${item.timestamp}.json` } }
  },
  // 6. Weather (최신)
  {
    json: { s3Key: item.s3Keys.weatherLatest, fileType: 'weather_latest' },
    binary: { data: { data: weatherBase64, mimeType: 'application/json', fileName: 'weather_current.json' } }
  },
  // 7. Flight Plans (타임스탬프)
  {
    json: { s3Key: item.s3Keys.flightPlans, fileType: 'fpl_timestamped' },
    binary: { data: { data: fplBase64, mimeType: 'application/json', fileName: `flight_plans_${item.timestamp}.json` } }
  },
  // 8. Flight Plans (최신)
  {
    json: { s3Key: item.s3Keys.flightPlansLatest, fileType: 'fpl_latest' },
    binary: { data: { data: fplBase64, mimeType: 'application/json', fileName: 'flight_schedule.json' } }
  },
  // 9. Aero Data (타임스탬프)
  {
    json: { s3Key: item.s3Keys.aeroData, fileType: 'aero_timestamped' },
    binary: { data: { data: aeroBase64, mimeType: 'application/json', fileName: `aero_data_${item.timestamp}.json` } }
  },
  // 10. Aero Data (최신)
  {
    json: { s3Key: item.s3Keys.aeroDataLatest, fileType: 'aero_latest' },
    binary: { data: { data: aeroBase64, mimeType: 'application/json', fileName: 'aero_data_current.json' } }
  }
];

// 업로드 결과 요약
const items = $input.all();
const successCount = items.filter(i => !i.json.error).length;
const errorCount = items.filter(i => i.json.error).length;

return [{
  json: {
    summary: `Supabase 업로드 완료: ${successCount}개 성공, ${errorCount}개 실패`,
    timestamp: new Date().toISOString(),
    totalFiles: items.length,
    success: successCount,
    errors: errorCount
  }
}];

// ===== 전체 크롤링 리포트 생성 =====
const item = $input.first().json;
const stats = item.stats;
const fullData = item.fullData;
const now = new Date();
const dateStr = now.toLocaleDateString('ko-KR');
const timeStr = now.toLocaleTimeString('ko-KR', { hour: '2-digit', minute: '2-digit' });

// NOTAM 상세
const notamData = fullData?.data?.notam || {};
let firTotal = 0;
Object.values(notamData.fir || {}).forEach(v => { firTotal += v?.records?.length || 0; });
let adTotal = 0;
Object.values(notamData.ad || {}).forEach(v => { adTotal += v?.records?.length || 0; });
const snowCount = notamData.snow?.records?.length || 0;
const prohibCount = notamData.prohibited?.records?.length || 0;
let seqTotal = 0;
Object.values(notamData.sequence || {}).forEach(v => { seqTotal += v?.records?.length || 0; });
const notamTotal = firTotal + adTotal + snowCount + prohibCount + seqTotal;

// Weather 상세
const weatherData = fullData?.data?.weather || {};
let metarTotal = 0;
Object.values(weatherData.metar || {}).forEach(v => { metarTotal += v?.records?.length || 0; });
let tafTotal = 0;
Object.values(weatherData.taf || {}).forEach(v => { tafTotal += v?.records?.length || 0; });
const sigmetCount = weatherData.sigmet?.records?.length || 0;
const weatherTotal = metarTotal + tafTotal + sigmetCount;

// FPL 상세
const fplData = fullData?.data?.flight_plans || {};
const ifrDep = fplData.ifr_departures?.records?.length || 0;
const ifrArr = fplData.ifr_arrivals?.records?.length || 0;
const vfr = fplData.vfr?.records?.length || 0;
const ulp = fplData.ulp_lsa?.records?.length || 0;
const fplTotal = ifrDep + ifrArr + vfr + ulp;

// AeroData 상세
const aeroData = fullData?.data?.aero_data || {};
const aptCount = Object.keys(aeroData.airports || {}).length;
const rwyCount = Object.keys(aeroData.runways || {}).length;
const apronCount = Object.keys(aeroData.aprons || {}).length;
const navaidCount = aeroData.navaids?.records?.length || 0;
const obstCount = aeroData.obstacles?.records?.length || 0;

// ATFM 상세
const atfmData = fullData?.data?.atfm || {};
const adpCount = atfmData.daily_plan?.records?.length || 0;
const dflCount = atfmData.messages?.records?.length || 0;

const grandTotal = notamTotal + weatherTotal + fplTotal + navaidCount + obstCount + adpCount + dflCount;

// 이메일 HTML
const emailHtml = `
<div style="font-family:'Segoe UI',Arial,sans-serif;max-width:700px;margin:0 auto">
  <div style="background:linear-gradient(135deg,#1a237e,#0d47a1);color:white;padding:20px;border-radius:8px 8px 0 0">
    <h2 style="margin:0">UBIKAIS 전체 크롤링 리포트</h2>
    <p style="margin:5px 0 0;opacity:.9">${dateStr} ${timeStr} | 총 ${grandTotal}건</p>
  </div>
  <div style="background:#f5f5f5;padding:20px;border:1px solid #ddd">
    <h3 style="color:#1a237e;border-bottom:2px solid #1a237e;padding-bottom:5px">NOTAM (${notamTotal}건)</h3>
    <table style="width:100%;border-collapse:collapse;margin-bottom:15px">
      <tr style="background:#e8eaf6"><th style="text-align:left;padding:6px">유형</th><th style="text-align:right;padding:6px">건수</th></tr>
      <tr><td style="padding:6px">FIR NOTAM (C/A/D)</td><td style="text-align:right;padding:6px">${firTotal}</td></tr>
      <tr style="background:#fafafa"><td style="padding:6px">AD NOTAM</td><td style="text-align:right;padding:6px">${adTotal}</td></tr>
      <tr><td style="padding:6px">SNOWTAM</td><td style="text-align:right;padding:6px">${snowCount}</td></tr>
      <tr style="background:#fafafa"><td style="padding:6px">금지구역</td><td style="text-align:right;padding:6px">${prohibCount}</td></tr>
      <tr><td style="padding:6px">Sequence</td><td style="text-align:right;padding:6px">${seqTotal}</td></tr>
    </table>

    <h3 style="color:#0d47a1;border-bottom:2px solid #0d47a1;padding-bottom:5px">기상 (${weatherTotal}건)</h3>
    <table style="width:100%;border-collapse:collapse;margin-bottom:15px">
      <tr style="background:#e3f2fd"><th style="text-align:left;padding:6px">유형</th><th style="text-align:right;padding:6px">건수</th></tr>
      <tr><td style="padding:6px">METAR</td><td style="text-align:right;padding:6px">${metarTotal}</td></tr>
      <tr style="background:#fafafa"><td style="padding:6px">TAF</td><td style="text-align:right;padding:6px">${tafTotal}</td></tr>
      <tr><td style="padding:6px">SIGMET</td><td style="text-align:right;padding:6px">${sigmetCount}</td></tr>
    </table>

    <h3 style="color:#1b5e20;border-bottom:2px solid #1b5e20;padding-bottom:5px">비행계획 (${fplTotal}건)</h3>
    <table style="width:100%;border-collapse:collapse;margin-bottom:15px">
      <tr style="background:#e8f5e9"><th style="text-align:left;padding:6px">유형</th><th style="text-align:right;padding:6px">건수</th></tr>
      <tr><td style="padding:6px">IFR 출발</td><td style="text-align:right;padding:6px">${ifrDep}</td></tr>
      <tr style="background:#fafafa"><td style="padding:6px">IFR 도착</td><td style="text-align:right;padding:6px">${ifrArr}</td></tr>
      <tr><td style="padding:6px">VFR</td><td style="text-align:right;padding:6px">${vfr}</td></tr>
      <tr style="background:#fafafa"><td style="padding:6px">ULP/LSA</td><td style="text-align:right;padding:6px">${ulp}</td></tr>
    </table>

    <h3 style="color:#e65100;border-bottom:2px solid #e65100;padding-bottom:5px">항공정보 (AeroData)</h3>
    <table style="width:100%;border-collapse:collapse;margin-bottom:15px">
      <tr style="background:#fff3e0"><th style="text-align:left;padding:6px">유형</th><th style="text-align:right;padding:6px">건수</th></tr>
      <tr><td style="padding:6px">공항</td><td style="text-align:right;padding:6px">${aptCount}개</td></tr>
      <tr style="background:#fafafa"><td style="padding:6px">활주로</td><td style="text-align:right;padding:6px">${rwyCount}개</td></tr>
      <tr><td style="padding:6px">에이프런</td><td style="text-align:right;padding:6px">${apronCount}개</td></tr>
      <tr style="background:#fafafa"><td style="padding:6px">NAVAID</td><td style="text-align:right;padding:6px">${navaidCount}</td></tr>
